__kernel void benchmark_func(T seed, __global T *g_data) {
  const size_t lid = get_local_id(0);
  const size_t gid = get_global_id(0);
  const size_t group_id = get_group_id(0);
  const size_t global_size = get_global_size(0);
  const size_t block_size = (size_t)blockdim;

#ifdef BLOCK_STRIDED
  const size_t stride = block_size;
  const size_t idx = group_id * block_size * (size_t)ELEMENTS_PER_THREAD + lid;
  const size_t big_stride =
      get_num_groups(0) * block_size * (size_t)ELEMENTS_PER_THREAD;
#else
  const size_t stride = global_size;
  const size_t idx = gid;
  const size_t big_stride = global_size * (size_t)ELEMENTS_PER_THREAD;
#endif

  T tmps[ELEMENTS_PER_THREAD];

  for (int k = 0; k < FUSION_DEGREE; ++k) {
    for (int j = 0; j < ELEMENTS_PER_THREAD; ++j) {
      tmps[j] = g_data[idx + (size_t)j * stride + (size_t)k * big_stride];

      for (int i = 0; i < COMPUTE_ITERATIONS; ++i) {
        tmps[j] = mad_fn(tmps[j], tmps[j], seed);
      }
    }

    T sum = conv_int_fn(0);
    for (int j = 0; j < ELEMENTS_PER_THREAD; j += 2) {
      sum = mad_fn(tmps[j], tmps[j + 1], sum);
    }

    if (equal_fn(sum, conv_int_fn(-1))) {
      g_data[idx + (size_t)k * big_stride] = sum;
    }
  }
}

